namespace sv_84aec53890fd45f1a2c45d1515db86e9.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _recipes = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with tomato, mozzarella, and basil.", 30),
            new(2, "Pasta Carbonara", "Creamy pasta with pancetta, egg, and Parmesan cheese.", 25),
            new(3, "Tiramisu", "Layered coffee-flavored Italian dessert.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and lime.", 20),
            new(5, "Green Curry", "Spicy coconut curry with vegetables and Thai basil.", 35),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass and prawns.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough pastry dusted with cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_recipes.TryGetValue(cuisineId, out var recipes))
            return recipes;

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_84aec53890fd45f1a2c45d1515db86e9.Services
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes for Cuisine @CuisineId</h1>

<div class="mb-3">
    <label class="form-label">Sort by:</label>
    <select class="form-select w-auto d-inline-block" value="@Sort" @onchange="OnSortChanged">
        <option value="newest">Newest</option>
        <option value="popular">Popular</option>
    </select>
</div>

@if (_isRefreshing && _recipes is not null)
{
    <div class="alert alert-info py-1 px-2 d-inline-block" role="status">
        Refreshing&hellip;
    </div>
}

@if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <div class="placeholder-glow">
        <p class="placeholder col-6"></p>
        <p class="placeholder col-8"></p>
        <p class="placeholder col-5"></p>
    </div>
}
else
{
    <div class="list-group">
        @foreach (var recipe in GetSortedRecipes())
        {
            <div class="list-group-item">
                <h5>@recipe.Title</h5>
                <p class="mb-1">@recipe.Description</p>
                <small class="text-muted">Prep time: @recipe.PrepTimeMinutes min</small>
            </div>
        }
    </div>

    @if (!_recipes.Any())
    {
        <p class="text-muted">No recipes found for this cuisine.</p>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only sort changed — no reload needed
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _errorMessage = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, token);

            if (token.IsCancellationRequested)
                return;

            _recipes = result;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // We cancelled this ourselves (new cuisine selected or navigating away) — ignore
        }
        catch (OperationCanceledException)
        {
            // External cancellation / timeout
            Logger.LogWarning("Recipe loading timed out for cuisine {CuisineId}", CuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes.OrderByDescending(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        var newSort = e.Value?.ToString() ?? "newest";
        Navigation.NavigateTo($"/recipes/{CuisineId}?sort={newSort}");
    }

    private async Task Retry()
    {
        _errorMessage = null;
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

